const res = await fetch('https://cloudcdn.pro/api/assets?project=akande&format=svg', {
  headers: { AccessKey: 'YOUR_ACCESS_KEY' }
});
const data = await res.json();
console.log(data.Data);

const file = await Deno.readFile('logo.svg'); // or fs.readFileSync
const res = await fetch('https://cloudcdn.pro/api/storage/clients/akande/v1/logos/new-logo.svg', {
  method: 'PUT',
  headers: { AccessKey: 'YOUR_ACCESS_KEY', 'Content-Type': 'application/octet-stream' },
  body: file
});
console.log(await res.json());

const res = await fetch('https://cloudcdn.pro/api/core/zones', {
  method: 'POST',
  headers: { AccountKey: 'YOUR_ACCOUNT_KEY', 'Content-Type': 'application/json' },
  body: JSON.stringify({ Name: 'newclient' })
});
console.log(await res.json());

